1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	type Step = QuoteStep | ClaimStep;
25	
26	interface Customer {
27	  yearsWithMHPCO: number;
28	}
29	
30	interface Scenario {
31	  customer: Customer;
32	  steps: Step[];
33	}
34	
35	interface QuoteResult {
36	  premium: number;
37	}
38	
39	interface ClaimResult {
40	  payout: number;
41	  remainingCap: number;
42	}
43	
44	type StepResult = QuoteResult | ClaimResult;
45	
46	const PROCESSING_FEE = 5;
47	const FIRST_INSURANCE_RATE = 0.1;
48	const LOYALTY_RATE = 0.2;
49	const LOYALTY_THRESHOLD_YEARS = 2;
50	const CURSED_RATE = 0.5;
51	const HIGH_ENCHANTMENT_RATE = 0.3;
52	const HIGH_ENCHANTMENT_THRESHOLD = 5;
53	const FOLLOW_UP_RATE = 0.15;
54	const BLOCK_SIZE = 3;
55	const BLOCK_BASE_PREMIUM = 60;
56	const DEDUCTIBLE = 100;
57	const CAP_MULTIPLIER = 2;
58	const HIGH_ENCHANTMENT_DAMAGE_THRESHOLD = 8;
59	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
60	
61	const BASE_PREMIUM: Record<string, number> = {
62	  sword: 100,
63	  amulet: 60,
64	  staff: 80,
65	  potion: 40,
66	  rune: 25,
67	  moonstone: 25,
68	};
69	
70	const INSURANCE_VALUE: Record<string, number> = {
71	  sword: 1000,
72	  amulet: 600,
73	  staff: 800,
74	  potion: 400,
75	  rune: 250,
76	  moonstone: 250,
77	};
78	
79	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
80	
81	const isBuildingBlock = (type: string, count: number): boolean =>
82	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
83	
84	const groupBasePremium = (type: string, count: number): number =>
85	  isBuildingBlock(type, count) ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUM[type];
86	
87	const countByType = (items: Item[]): Map<string, number> =>
88	  items.reduce(
89	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
90	    new Map<string, number>(),
91	  );
92	
93	const policyBase = (items: Item[]): number =>
94	  Array.from(countByType(items)).reduce(
95	    (total, [type, count]) => total + groupBasePremium(type, count),
96	    0,
97	  );
98	
99	const SURCHARGE_RATES: ReadonlyArray<(item: Item) => number> = [
100	  (item) => (item.cursed ? CURSED_RATE : 0),
101	  (item) => ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0),
102	];
103	
104	const itemSurcharges = (item: Item): number => {
105	  const itemBase = BASE_PREMIUM[item.type];
106	  const totalRate = SURCHARGE_RATES.reduce((sum, rate) => sum + rate(item), 0);
107	  return itemBase * totalRate;
108	};
109	
110	const policySurcharges = (items: Item[]): number =>
111	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
112	
113	const firstInsuranceSurcharge = (base: number): number => base * FIRST_INSURANCE_RATE;
114	
115	const loyaltyDiscount = (customer: Customer, base: number): number =>
116	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_RATE : 0;
117	
118	const followUpDiscount = (quoteIndex: number, base: number): number =>
119	  quoteIndex > 0 ? base * FOLLOW_UP_RATE : 0;
120	
121	const computePremium = (customer: Customer, quoteIndex: number, items: Item[]): number => {
122	  const base = policyBase(items);
123	  const surcharges = policySurcharges(items) + firstInsuranceSurcharge(base);
124	  const discounts = loyaltyDiscount(customer, base) + followUpDiscount(quoteIndex, base);
125	  return Math.ceil(base + surcharges - discounts + PROCESSING_FEE);
126	};
127	
128	interface Policy {
129	  items: Item[];
130	  remainingCap: number;
131	}
132	
133	const assertKnownType = (type: string): void => {
134	  if (!(type in BASE_PREMIUM)) {
135	    throw new Error(`Unknown item type: ${type}`);
136	  }
137	};
138	
139	const createPolicy = (items: Item[]): Policy => {
140	  items.forEach((item) => assertKnownType(item.type));
141	  const insuranceSum = items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
142	  return { items: [...items], remainingCap: insuranceSum * CAP_MULTIPLIER };
143	};
144	
145	const damagePayout = (damage: Damage, item: Item): number => {
146	  if (damage.amount < 0) {
147	    throw new Error(`Negative damage amount: ${damage.amount}`);
148	  }
149	  const reimbursementRate = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_DAMAGE_THRESHOLD
150	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
151	    : 1;
152	  const reimbursed = damage.amount * reimbursementRate;
153	  return Math.max(0, reimbursed - DEDUCTIBLE);
154	};
155	
156	const matchDamagesToItems = (policy: Policy, damages: Damage[]): Item[] => {
157	  const available = [...policy.items];
158	  return damages.map((d) => {
159	    const idx = available.findIndex((it) => it.type === d.itemType);
160	    if (idx === -1) {
161	      throw new Error(`Damaged item ${d.itemType} is not part of the policy`);
162	    }
163	    const [item] = available.splice(idx, 1);
164	    return item;
165	  });
166	};
167	
168	const processClaim = (policy: Policy, step: ClaimStep): ClaimResult => {
169	  const items = matchDamagesToItems(policy, step.incident.damages);
170	  const grossPayout = step.incident.damages.reduce(
171	    (sum, d, i) => sum + damagePayout(d, items[i]),
172	    0,
173	  );
174	  const finalPayout = Math.min(Math.floor(grossPayout), policy.remainingCap);
175	  policy.remainingCap -= finalPayout;
176	  return { payout: finalPayout, remainingCap: policy.remainingCap };
177	};
178	
179	export const processScenario = (scenario: Scenario): { results: StepResult[] } => {
180	  const policies = new Map<number, Policy>();
181	  let quoteIndex = 0;
182	  const results: StepResult[] = scenario.steps.map((step, stepIndex) => {
183	    if (step.op === "quote") {
184	      step.items.forEach((item) => assertKnownType(item.type));
185	      const premium = computePremium(scenario.customer, quoteIndex, step.items);
186	      quoteIndex += 1;
187	      policies.set(stepIndex, createPolicy(step.items));
188	      return { premium };
189	    }
190	    return processClaim(policies.get(step.policy)!, step);
191	  });
192	  return { results };
193	};
